const https = require('https');
const data = $('Fetch /export').first().json;
const jsonStr = JSON.stringify(data);
const fileBytes = Buffer.from(jsonStr, 'utf8');

const now = new Date();
const pad = n => String(n).padStart(2, '0');
const ts = now.getFullYear() + pad(now.getMonth()+1) + pad(now.getDate()) + '_' + pad(now.getHours()) + pad(now.getMinutes()) + pad(now.getSeconds());
const basePath = '/mnt/House48_NAS/Kitchenaid-Web/backup-data';
const dstPath = basePath + '/ka-data-' + ts + '.json';
const latestPath = basePath + '/ka-data-latest.json';

async function uploadOne(targetPath) {
  const boundary = 'Boundary' + Date.now() + Math.random().toString(36).slice(2);
  const dataJson = JSON.stringify({ method: 'filesystem.put', params: [targetPath] });
  const CRLF = '\r\n';
  const pre = Buffer.from(
    '--' + boundary + CRLF +
    'Content-Disposition: form-data; name="data"' + CRLF + CRLF +
    dataJson + CRLF +
    '--' + boundary + CRLF +
    'Content-Disposition: form-data; name="file"; filename="backup.json"' + CRLF +
    'Content-Type: application/json' + CRLF + CRLF,
    'utf8'
  );
  const post = Buffer.from(CRLF + '--' + boundary + '--' + CRLF, 'utf8');
  const body = Buffer.concat([pre, fileBytes, post]);
  const auth = Buffer.from('truenas_admin:023023As').toString('base64');
  return new Promise((resolve, reject) => {
    const req = https.request({
      hostname: '192.168.1.143',
      port: 443,
      path: '/_upload',
      method: 'POST',
      rejectUnauthorized: false,
      headers: {
        'Authorization': 'Basic ' + auth,
        'Content-Type': 'multipart/form-data; boundary=' + boundary,
        'Content-Length': body.length
      }
    }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        const respStr = Buffer.concat(chunks).toString('utf8');
        if (res.statusCode >= 200 && res.statusCode < 300) resolve(respStr);
        else reject(new Error('HTTP ' + res.statusCode + ': ' + respStr));
      });
    });
    req.on('error', reject);
    req.write(body);
    req.end();
  });
}

const r1 = await uploadOne(dstPath);
const r2 = await uploadOne(latestPath);
return [{ json: { ok: true, ts, dstPath, latestPath, sizeBytes: fileBytes.length, timestamped: r1, latest: r2 } }];
